#!/bin/sh
# gen-passphrase.sh — generate a diceware-style passphrase from common English words
#
# Usage:
#   gen-passphrase.sh           Generate 12-word passphrase (~120 bits entropy)
#   gen-passphrase.sh 6         Generate 6-word passphrase  (~60 bits entropy)
#
# Uses an embedded 1024-word common-English list (~10 bits per word).
# Portable: works on OpenBSD, Linux, macOS — no shuf or external wordlist needed.

WORDS="${1:-12}"

# 1024 common English words (4-8 chars, all recognizable)
WORDLIST="able about above accept across acting action active actual added admit adult after again agree ahead allow almost alone along already also always among amount animal answer appear apple apply area army around arrive asked atlas avoid awake away back badge baked ball bank bare base basic batch beach bear beat began begin being below bench best beyond bike bird black blade blame blank blast blaze block blood blown board body bone book border born both bottom bound brain brave bread break brick brief bring broad broke brown brush buddy build bunch burn burst cabin cabin cable calm came camp candy capture card carry catch cause chain chair chalk change chase cheap check chest chief child china chips chord chose chunk city civil claim class clean clear clerk click cliff climb clock close cloud coach coast coin cold color combo comes comic cool coral core could count court cover crack craft crash crazy cream crew cross crowd crown crush cubic curve cycle daily dance dare dark data deal death debug delay delta dense depth derby design desk diet dirty ditch dodge doing done doubt dozen draft drain drama drawn dream dress dried drift drink drive drops drum dying each earl early earth ease east easy edge eight elder empty ended enemy enjoy enter equal error essay even event every exact exist extra face fact faith fall fancy fatal fault fear feast felt fence ferry fetch fewer field fight file final find fine fire first fixed flag flame flash flat flesh flies flip float flood floor flow fluid foam focus fold folk food force forge form forth found four frame frank free fresh front frost fruit fuel full funny gain game gang gate gave gear ghost giant gift given glad glass globe gloom glory going gold gone good grab grace grade grain grand grant grape grasp grave great green grew grid grill grip group grove grown guard guess guide habit half hand hang happy hard hate have head heard heart heavy hence high hint hire hold hole home honor hope horse hotel hours house human 