k trust truth turns twice twist types under union unite until upper upset urban usage valid value vault verse video vigor viral visit vital vivid voice voter wagon watch water waves wheel where which while white whole whose wider wind witch woman world worth would write wrong yield young youth</WORDLIST>"

# Use /dev/urandom for proper randomness (awk srand() is too predictable)
TOTAL=$(echo "$WORDLIST" | tr ' ' '\n' | wc -l)
for i in $(od -A n -t u4 -N $((WORDS * 4)) /dev/urandom | tr -s ' ' '\n' | grep .); do
    INDEX=$(( (i % TOTAL) + 1 ))
    echo "$WORDLIST" | tr ' ' '\n' | sed -n "${INDEX}p"
done | tr '\n' ' ' | sed 's/ $/\n/'
